ALTER TABLE `pool_retrospectives` ADD COLUMN IF NOT EXISTS `videoUrl` text;
ALTER TABLE `pool_retrospectives` ADD COLUMN IF NOT EXISTS `videoKey` varchar(255);
ALTER TABLE `pool_retrospectives` ADD COLUMN IF NOT EXISTS `videoStatus` enum('pending','processing','done','failed') DEFAULT 'pending' NOT NULL;

ALTER TABLE `retrospective_config` ADD COLUMN IF NOT EXISTS `enableSlides` boolean DEFAULT true NOT NULL;
ALTER TABLE `retrospective_config` ADD COLUMN IF NOT EXISTS `enableVideo` boolean DEFAULT false NOT NULL;
ALTER TABLE `retrospective_config` ADD COLUMN IF NOT EXISTS `videoQuality` enum('low','medium','high') DEFAULT 'medium' NOT NULL;
ALTER TABLE `retrospective_config` ADD COLUMN IF NOT EXISTS `testVideoUrl` text;

